export interface Game {
  id: string;
  home_team: string;
  away_team: string;
  commence_time: string;
}

export interface Outcome {
  name: string;
  description?: string; // Player name often lives here
  price: number;
  point?: number;
}

export interface Market {
  key: string;
  last_update: string;
  outcomes: Outcome[];
}

export interface Bookmaker {
  key: string;
  title: string;
  markets: Market[];
}

export interface OddsResponse {
  id: string;
  sport_key: string;
  sport_title: string;
  commence_time: string;
  home_team: string;
  away_team: string;
  bookmakers: Bookmaker[];
}

export interface PlayerProp {
  playerName: string;
  marketKey: string;
  line: number;
  overPrice?: number;
  underPrice?: number;
}

export enum ViewState {
  API_SETUP = 'api_setup',
  GAMES_LIST = 'games_list',
  GAME_DETAIL = 'game_detail'
}

import { Game, OddsResponse } from '../types';

const BASE_URL = 'https://api.the-odds-api.com/v4/sports/basketball_nba';

export const fetchNbaEvents = async (apiKey: string, signal?: AbortSignal): Promise<Game[]> => {
  const response = await fetch(`${BASE_URL}/events?apiKey=${apiKey}`, { signal });
  if (!response.ok) {
    if (response.status === 401) throw new Error('Invalid API Key');
    if (response.status === 429) throw new Error('Rate limit exceeded');
    throw new Error('Failed to fetch NBA events');
  }
  return response.json();
};

export const fetchOddsForGame = async (
  apiKey: string,
  eventId: string,
  markets: string = 'h2h,spreads,totals',
  signal?: AbortSignal
): Promise<OddsResponse> => {
  const response = await fetch(
    `${BASE_URL}/events/${eventId}/odds?apiKey=${apiKey}&regions=us&markets=${markets}&oddsFormat=american`,
    { signal }
  );
  if (!response.ok) {
    throw new Error('Failed to fetch odds');
  }
  const data = await response.json();
  // Returns a single object for that event id
  return data;
};

import React, { createContext, useContext, useState, useCallback, ReactNode } from 'react';

interface ApiKeyContextType {
  apiKey: string | null;
  saveKey: (key: string) => void;
  clearKey: () => void;
}

const ApiKeyContext = createContext<ApiKeyContextType | undefined>(undefined);

export const ApiKeyProvider: React.FC<{ children: ReactNode }> = ({ children }) => {
  const [apiKey, setApiKey] = useState<string | null>(() => localStorage.getItem('odds_api_key'));

  const saveKey = useCallback((key: string) => {
    localStorage.setItem('odds_api_key', key);
    setApiKey(key);
  }, []);

  const clearKey = useCallback(() => {
    localStorage.removeItem('odds_api_key');
    setApiKey(null);
  }, []);

  return (
    <ApiKeyContext.Provider value={{ apiKey, saveKey, clearKey }}>
      {children}
    </ApiKeyContext.Provider>
  );
};

export const useApiKey = () => {
  const context = useContext(ApiKeyContext);
  if (!context) throw new Error('useApiKey must be used within ApiKeyProvider');
  return context;
};

import { useState, useEffect, useCallback } from 'react';
import { Game } from '../types';
import { fetchNbaEvents } from '../api/oddsApi';
import { useApiKey } from '../context/ApiKeyContext';

export const useEvents = () => {
  const { apiKey } = useApiKey();
  const [events, setEvents] = useState<Game[]>([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const loadEvents = useCallback(async (signal?: AbortSignal) => {
    if (!apiKey) return;
    setLoading(true);
    setError(null);
    try {
      const data = await fetchNbaEvents(apiKey, signal);
      setEvents(data);
    } catch (err: any) {
      if (err.name !== 'AbortError') {
        setError(err.message);
      }
    } finally {
      setLoading(false);
    }
  }, [apiKey]);

  useEffect(() => {
    const controller = new AbortController();
    loadEvents(controller.signal);
    return () => controller.abort();
  }, [loadEvents]);

  return { events, loading, error, refresh: loadEvents };
};

import { useState, useEffect, useCallback } from 'react';
import { OddsResponse } from '../types';
import { fetchOddsForGame } from '../api/oddsApi';
import { useApiKey } from '../context/ApiKeyContext';

export const useOdds = (eventId: string | null, markets: string) => {
  const { apiKey } = useApiKey();
  const [data, setData] = useState<OddsResponse | null>(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const loadOdds = useCallback(async (signal?: AbortSignal) => {
    if (!apiKey || !eventId) return;
    setLoading(true);
    setError(null);
    try {
      const response = await fetchOddsForGame(apiKey, eventId, markets, signal);
      setData(response);
    } catch (err: any) {
      if (err.name !== 'AbortError') {
        setError(err.message);
      }
    } finally {
      setLoading(false);
    }
  }, [apiKey, eventId, markets]);

  useEffect(() => {
    const controller = new AbortController();
    loadOdds(controller.signal);
    return () => controller.abort();
  }, [loadOdds]);

  return { data, loading, error, refresh: loadOdds };
};

import { GoogleGenAI } from "@google/genai";

export const analyzeOddsWithGemini = async (oddsData: any): Promise<string> => {
  if (!process.env.API_KEY) return "Gemini API key missing.";

  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const model = 'gemini-3-flash-preview';

  try {
    const prompt = `
      Analyze these NBA odds data and provide a concise 3-sentence summary of the betting landscape.
      Identify if there is a strong favorite or if the lines are tight.
      Data: ${JSON.stringify(oddsData)}
    `;

    const response = await ai.models.generateContent({
      model,
      contents: prompt,
    });

    return response.text || "Unable to generate analysis.";
  } catch (err) {
    console.error("Gemini Error:", err);
    return "Failed to analyze data with Gemini.";
  }
};

import React, { useState, useCallback } from 'react';
import { useApiKey } from '../context/ApiKeyContext';

const ApiKeySetup: React.FC = () => {
  const [inputValue, setInputValue] = useState('');
  const { saveKey } = useApiKey();

  const handleSubmit = useCallback((e: React.FormEvent) => {
    e.preventDefault();
    if (inputValue.trim()) {
      saveKey(inputValue.trim());
    }
  }, [inputValue, saveKey]);

  return (
    <div className="flex flex-col items-center justify-center h-screen bg-white px-4">
      <div className="w-full max-w-sm border border-black p-6">
        <h1 className="text-xl font-bold mb-4 uppercase tracking-tighter">NBA Odds Engine</h1>
        <p className="text-sm mb-6 text-gray-600">Enter your The-Odds-API key to continue.</p>
        <form onSubmit={handleSubmit} className="flex flex-col gap-4">
          <input
            type="password"
            placeholder="API Key"
            className="border border-black p-2 outline-none focus:bg-gray-50"
            value={inputValue}
            onChange={(e) => setInputValue(e.target.value)}
          />
          <button
            type="submit"
            className="bg-black text-white p-2 font-bold uppercase hover:bg-gray-800 disabled:opacity-50"
            disabled={!inputValue.trim()}
          >
            Access Data
          </button>
        </form>
      </div>
    </div>
  );
};

export default ApiKeySetup;

import React from 'react';
import { useEvents } from '../hooks/useEvents';
import { Game } from '../types';

interface GamesProps {
  onSelectGame: (game: Game) => void;
}

const Games: React.FC<GamesProps> = ({ onSelectGame }) => {
  const { events, loading, error, refresh } = useEvents();

  if (loading) return <div className="p-4 uppercase text-xs">Loading Games...</div>;
  if (error) return <div className="p-4 text-red-500 uppercase text-xs">Error: {error}</div>;

  return (
    <div className="flex flex-col min-h-screen bg-white">
      <header className="border-b border-black p-4 flex justify-between items-center sticky top-0 bg-white z-10">
        <h1 className="font-bold uppercase tracking-tighter">NBA Schedule</h1>
        <button onClick={() => refresh()} className="text-xs border border-black px-2 py-1 uppercase">Refresh</button>
      </header>
      <main className="flex-1">
        {events.length === 0 ? (
          <div className="p-4 text-gray-500 uppercase text-xs">No upcoming games found.</div>
        ) : (
          events.map((game) => (
            <div
              key={game.id}
              onClick={() => onSelectGame(game)}
