                <span>{game.away_team} @ {game.home_team}</span>
              </div>
              <div className="text-xs text-gray-500">
                {new Date(game.commence_time).toLocaleString()}
              </div>
            </div>
          ))
        )}
      </main>
    </div>
  );
};

export default Games;

import React, { useState, useMemo, useCallback } from 'react';
import { Game, PlayerProp } from '../types';
import { useOdds } from '../hooks/useOdds';
import { analyzeOddsWithGemini } from '../services/geminiService';

interface GameDetailProps {
  game: Game;
  onBack: () => void;
}

type Tab = 'TEAM' | 'PLAYER';

const GameDetail: React.FC<GameDetailProps> = ({ game, onBack }) => {
  const [activeTab, setActiveTab] = useState<Tab>('TEAM');
  const [analysis, setAnalysis] = useState<string | null>(null);
  const [analyzing, setAnalyzing] = useState(false);

  // Load team odds or player props based on active tab
  const marketsString = useMemo(() => {
    return activeTab === 'TEAM' 
      ? 'h2h,spreads,totals' 
      : 'player_points,player_assists,player_rebounds';
  }, [activeTab]);

  const { data, loading, error } = useOdds(game.id, marketsString);

  const playerProps = useMemo(() => {
    if (activeTab !== 'PLAYER' || !data) return [];

    const props: PlayerProp[] = [];
    data.bookmakers.forEach(bookie => {
      bookie.markets.forEach(market => {
        // Group outcomes by description (player name) and point (line)
        const grouped = market.outcomes.reduce((acc: any, outcome) => {
          const playerName = outcome.description || 'Unknown';
          const line = outcome.point || 0;
          const key = `${playerName}_${line}_${market.key}`;

          if (!acc[key]) acc[key] = { playerName, marketKey: market.key, line };

          if (outcome.name === 'Over') acc[key].overPrice = outcome.price;
          if (outcome.name === 'Under') acc[key].underPrice = outcome.price;

          return acc;
        }, {});

        Object.values(grouped).forEach((p: any) => props.push(p as PlayerProp));
      });
    });
    return props;
  }, [data, activeTab]);

  const handleAnalyze = useCallback(async () => {
    if (!data) return;
    setAnalyzing(true);
    const result = await analyzeOddsWithGemini(data);
    setAnalysis(result);
    setAnalyzing(false);
  }, [data]);

  return (
    <div className="flex flex-col min-h-screen bg-white pb-10">
      <header className="border-b border-black p-4 flex items-center sticky top-0 bg-white z-10 gap-4">
        <button onClick={onBack} className="text-xs border border-black px-2 py-1 uppercase">Back</button>
        <h1 className="font-bold uppercase tracking-tighter truncate">
          {game.away_team} @ {game.home_team}
        </h1>
      </header>

      <div className="flex border-b border-black bg-gray-50">
        <button
          onClick={() => setActiveTab('TEAM')}
          className={`flex-1 p-3 text-xs font-bold uppercase ${activeTab === 'TEAM' ? 'bg-black text-white' : 'bg-transparent text-black'}`}
        >
          Team Odds
        </button>
        <button
          onClick={() => setActiveTab('PLAYER')}
          className={`flex-1 p-3 text-xs font-bold uppercase ${activeTab === 'PLAYER' ? 'bg-black text-white' : 'bg-transparent text-black'}`}
        >
          Player Props
        </button>
      </div>

      <main className="p-4">
        {loading && <div className="text-xs uppercase">Loading market data...</div>}
        {error && <div className="text-xs uppercase text-red-500">Error: {error}</div>}

        {!loading && !error && data && (
          <div className="flex flex-col gap-6">
            <section className="border border-black p-3 bg-gray-50">
              <h2 className="text-xs font-bold uppercase mb-2">Gemini Insight</h2>
              {analysis ? (
                <p className="text-xs leading-relaxed italic">"{analysis}"</p>
              ) : (
                <button 
                  onClick={handleAnalyze} 
                  disabled={analyzing}
                  className="text-[10px] border border-black px-2 py-1 uppercase hover:bg-black hover:text-white disabled:opacity-50"
                >
                  {analyzing ? 'Analyzing...' : 'Generate Analysis'}
                </button>
              )}
            </section>

            {activeTab === 'TEAM' ? (
              <div className="flex flex-col gap-4">
                {data.bookmakers.length === 0 ? (
                   <div className="text-xs uppercase text-gray-400">No team odds available yet.</div>
                ) : (
                  data.bookmakers.slice(0, 3).map(bookie => (
                    <div key={bookie.key} className="border border-gray-200 p-3">
                      <div className="text-[10px] font-bold uppercase mb-2 border-b border-gray-100 pb-1">{bookie.title}</div>
                      <div className="grid grid-cols-1 gap-2">
                        {bookie.markets.map(market => (
                          <div key={market.key} className="flex justify-between items-center text-xs">
                            <span className="uppercase text-gray-500 font-mono">{market.key}:</span>
                            <div className="flex gap-2">
                              {market.outcomes.map((o, i) => (
                                <span key={i} className="font-bold">
                                  {o.name} {o.point !== undefined ? `(${o.point})` : ''} @ {o.price}
                                </span>
                              ))}
                            </div>
                          </div>
                        ))}
                      </div>
                    </div>
                  ))
                )}
              </div>
            ) : (
              <div className="flex flex-col gap-2">
                {playerProps.length === 0 ? (
                  <div className="text-xs uppercase text-gray-400">Player props not yet available.</div>
                ) : (
                  playerProps.map((prop, i) => (
                    <div key={i} className="border-b border-gray-100 py-2 flex justify-between items-center text-xs">
                      <div>
                        <div className="font-bold uppercase">{prop.playerName}</div>
                        <div className="text-[10px] text-gray-500 uppercase">{prop.marketKey.replace('player_', '')} {prop.line}</div>
                      </div>
                      <div className="flex gap-4 font-mono font-bold">
                        {prop.overPrice && <div className="flex flex-col items-end">
                          <span className="text-[8px] text-gray-400 uppercase">Over</span>
                          <span>{prop.overPrice}</span>
                        </div>}
                        {prop.underPrice && <div className="flex flex-col items-end">
                          <span className="text-[8px] text-gray-400 uppercase">Under</span>
                          <span>{prop.underPrice}</span>
                        </div>}
                      </div>
                    </div>
                  ))
                )}
              </div>
            )}
          </div>
        )}
      </main>
    </div>
  );
};

export default GameDetail;

import React, { useState } from 'react';
import { ApiKeyProvider, useApiKey } from './context/ApiKeyContext';
import { ViewState, Game } from './types';
import ApiKeySetup from './pages/ApiKeySetup';
import Games from './pages/Games';
import GameDetail from './pages/GameDetail';

const Router: React.FC = () => {
  const { apiKey } = useApiKey();
  const [selectedGame, setSelectedGame] = useState<Game | null>(null);

  // Basic state-based routing for performance and simplicity
  if (!apiKey) {
    return <ApiKeySetup />;
  }

  if (selectedGame) {
    return <GameDetail game={selectedGame} onBack={() => setSelectedGame(null)} />;
  }

  return <Games onSelectGame={(game) => setSelectedGame(game)} />;
};

const App: React.FC = () => {
  return (
    <ApiKeyProvider>
      <div className="max-w-xl mx-auto min-h-screen border-x border-black bg-white">
        <Router />
      </div>
    </ApiKeyProvider>
  );
};

export default App;

import React, { useState, useMemo, useCallback } from 'react';
import { Game, PlayerProp } from '../types';
import { useOdds } from '../hooks/useOdds';
import { analyzeOddsWithGemini } from '../services/geminiService';

interface GameDetailProps {
  game: Game;
  onBack: () => void;
}

type Tab = 'TEAM' | 'PLAYER';

const GameDetail: React.FC<GameDetailProps> = ({ game, onBack }) => {
  const [activeTab, setActiveTab] = useState<Tab>('TEAM');
  const [analysis, setAnalysis] = useState<string | null>(null);
  const [analyzing, setAnalyzing] = useState(false);

  // Load team odds or player props based on active tab
  const marketsString = useMemo(() => {
    return activeTab === 'TEAM' 
      ? 'h2h,spreads,totals' 
      : 'player_points,player_assists,player_rebounds';
  }, [activeTab]);

  const { data, loading, error } = useOdds(game.id, marketsString);

  // Grouped player props logic
  const groupedPlayerProps = useMemo(() => {
    if (activeTab !== 'PLAYER' || !data) return {};

    const groups: Record<string, PlayerProp[]> = {};

    data.bookmakers.forEach(bookie => {
      bookie.markets.forEach(market => {
        // First consolidate Over/Under outcomes for the same line
        const marketOutcomesGrouped = market.outcomes.reduce((acc: any, outcome) => {
          const playerName = outcome.description || 'Unknown';
          const line = outcome.point || 0;
          const key = `${playerName}_${line}_${market.key}`;

          if (!acc[key]) acc[key] = { playerName, marketKey: market.key, line };

          if (outcome.name === 'Over') acc[key].overPrice = outcome.price;
          if (outcome.name === 'Under') acc[key].underPrice = outcome.price;

          return acc;
        }, {});

        // Then add to the main player group
        Object.values(marketOutcomesGrouped).forEach((p: any) => {
          const prop = p as PlayerProp;
          if (!groups[prop.playerName]) {
            groups[prop.playerName] = [];
          }
          groups[prop.playerName].push(prop);
        });
      });
    });

    return groups;
  }, [data, activeTab]);

  const handleAnalyze = useCallback(async () => {
    if (!data) return;
    setAnalyzing(true);
    const result = await analyzeOddsWithGemini(data);
    setAnalysis(result);
    setAnalyzing(false);
  }, [data]);

  return (
    <div style={{ display: 'flex', flexDirection: 'column', minHeight: '100vh', paddingBottom: '40px' }}>
      <header>
        <div style={{ display: 'flex', alignItems: 'center', gap: '16px' }}>
          <button onClick={onBack}>Back</button>
          <h1 style={{ margin: 0, fontSize: '16px', fontWeight: 'bold', textTransform: 'uppercase', whiteSpace: 'nowrap', overflow: 'hidden', textOverflow: 'ellipsis' }}>
            {game.away_team} @ {game.home_team}
          </h1>
        </div>
      </header>

      <div className="tabs">
        <button
          onClick={() => setActiveTab('TEAM')}
          className={`tab-button ${activeTab === 'TEAM' ? 'active' : ''}`}
        >
          Team Odds
        </button>
        <button
          onClick={() => setActiveTab('PLAYER')}
          className={`tab-button ${activeTab === 'PLAYER' ? 'active' : ''}`}
        >
          Player Props
        </button>
      </div>

      <main style={{ padding: '16px' }}>
        {loading && <div style={{ fontSize: '11px', textTransform: 'uppercase' }}>Loading market data...</div>}
        {error && <div style={{ fontSize: '11px', textTransform: 'uppercase', color: 'red' }}>Error: {error}</div>}

        {!loading && !error && data && (
          <div style={{ display: 'flex', flexDirection: 'column', gap: '24px' }}>
            <section className="section-box">
              <h2 style={{ fontSize: '11px', fontWeight: 'bold', textTransform: 'uppercase', marginBottom: '8px', marginTop: 0 }}>Gemini Insight</h2>
              {analysis ? (
                <p style={{ fontSize: '11px', lineHeight: '1.5', fontStyle: 'italic', margin: 0 }}>"{analysis}"</p>
              ) : (
                <button 
                  onClick={handleAnalyze} 
                  disabled={analyzing}
                  style={{ fontSize: '10px' }}
                >
                  {analyzing ? 'Analyzing...' : 'Generate Analysis'}
                </button>
              )}
            </section>

            {activeTab === 'TEAM' ? (
              <div style={{ display: 'flex', flexDirection: 'column', gap: '16px' }}>
                {data.bookmakers.length === 0 ? (
                   <div style={{ fontSize: '11px', textTransform: 'uppercase', color: '#999' }}>No team odds available yet.</div>
                ) : (
                  data.bookmakers.slice(0, 3).map(bookie => (
                    <div key={bookie.key} style={{ border: '1px solid #eee', padding: '12px' }}>
                      <div style={{ fontSize: '10px', fontWeight: 'bold', textTransform: 'uppercase', marginBottom: '8px', borderBottom: '1px solid #f0f0f0', paddingBottom: '4px' }}>{bookie.title}</div>
                      <div style={{ display: 'flex', flexDirection: 'column', gap: '8px' }}>
                        {bookie.markets.map(market => (
                          <div key={market.key} style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', fontSize: '11px' }}>
                            <span style={{ textTransform: 'uppercase', color: '#666', fontFamily: 'monospace' }}>{market.key}:</span>
                            <div style={{ display: 'flex', gap: '8px' }}>
                              {market.outcomes.map((o, i) => (
                                <span key={i} style={{ fontWeight: 'bold' }}>
                                  {o.name} {o.point !== undefined ? `(${o.point})` : ''} @ {o.price}
                                </span>
                              ))}
                            </div>
                          </div>
                        ))}
                      </div>
                    </div>
                  ))
                )}
              </div>
            ) : (
              <div style={{ display: 'flex', flexDirection: 'column' }}>
                {Object.entries(groupedPlayerProps).length === 0 ? (
                  <div style={{ fontSize: '11px', textTransform: 'uppercase', color: '#999' }}>Player props not yet available.</div>
                ) : (
                  Object.entries(groupedPlayerProps).map(([playerName, props], i) => (
                    <div key={playerName} className="player-group">
                      <div className="player-header">{playerName}</div>
                      <div style={{ display: 'flex', flexDirection: 'column' }}>
                        {props.map((prop, j) => (
                          <div key={j} className="prop-row">
                            <div>
                              <span className="prop-label">{prop.marketKey.replace('player_', '').replace('_', ' ')}</span>
                              <span style={{ marginLeft: '8px', fontWeight: 'bold' }}>{prop.line}</span>
                            </div>
                            <div className="odds-grid">
                              {prop.overPrice && (
                                <div style={{ textAlign: 'right' }}>
                                  <span className="label-tiny">Over</span>
                                  <span>{prop.overPrice}</span>
                                </div>
                              )}
                              {prop.underPrice && (
                                <div style={{ textAlign: 'right' }}>
                                  <span className="label-tiny">Under</span>
                                  <span>{prop.underPrice}</span>
                                </div>
                              )}
                            </div>
                          </div>
                        ))}
                      </div>
                    </div>
                  ))
                )}
              </div>
            )}
          </div>
        )}
      </main>
    </div>
  );
};

export default GameDetail;

import React, { useState } from 'react';
import { ApiKeyProvider, useApiKey } from './context/ApiKeyContext';
import { ViewState, Game } from './types';
import ApiKeySetup from './pages/ApiKeySetup';
import Games from './pages/Games';
import GameDetail from './pages/GameDetail';

const Router: React.FC = () => {
  const { apiKey } = useApiKey();
  const [selectedGame, setSelectedGame] = useState<Game | null>(null);

  if (!apiKey) {
    return <ApiKeySetup />;
  }

  if (selectedGame) {
    return <GameDetail game={selectedGame} onBack={() => setSelectedGame(null)} />;
  }

