import { Game, OddsResponse } from '../types';

const BASE_URL = 'https://api.the-odds-api.com/v4/sports/basketball_nba';

export const fetchNbaEvents = async (apiKey: string, signal?: AbortSignal): Promise<Game[]> => {
  const url = `${BASE_URL}/events?apiKey=${apiKey}`;
  console.debug(`Fetching NBA Events: ${url.replace(apiKey, 'REDACTED')}`);

  const response = await fetch(url, { signal });

  if (!response.ok) {
    const errorBody = await response.text().catch(() => 'No error body');
    console.error(`Fetch NBA Events Error [${response.status}]:`, errorBody);

    if (response.status === 401) throw new Error('Invalid API Key');
    if (response.status === 429) throw new Error('Rate limit exceeded');
    throw new Error(`Failed to fetch NBA events: ${response.status} ${response.statusText}`);
  }

  return response.json();
};

export const fetchOddsForGame = async (
  apiKey: string,
  eventId: string,
  markets: string = 'h2h,spreads,totals',
  signal?: AbortSignal
): Promise<OddsResponse> => {
  const url = `${BASE_URL}/events/${eventId}/odds?apiKey=${apiKey}&regions=us&markets=${markets}&oddsFormat=american`;
  console.debug(`Fetching Odds for ${eventId}: ${url.replace(apiKey, 'REDACTED')}`);

  const response = await fetch(url, { signal });

  if (!response.ok) {
    const errorBody = await response.text().catch(() => 'No error body');
    console.error(`Fetch Odds Error [${response.status}] for event ${eventId}:`, errorBody);

    if (response.status === 401) throw new Error('Invalid API Key');
    if (response.status === 422) throw new Error('Unprocessable Entity: Check if event ID or markets are valid for your subscription');
    if (response.status === 429) throw new Error('Rate limit exceeded');

    throw new Error(`Failed to fetch odds: ${response.status} ${response.statusText}`);
  }

  const data = await response.json();
  return data;
};

import { GoogleGenAI } from "@google/genai";

/**
 * Analyzes NBA odds data using Gemini 3 Flash.
 * Follows Google GenAI SDK guidelines for instantiation and content generation.
 */
export const analyzeOddsWithGemini = async (oddsData: any): Promise<string> => {
  // Use process.env.API_KEY which is pre-configured.
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  try {
    const prompt = `
      Analyze these NBA odds data and provide a concise 3-sentence summary of the betting landscape.
      Identify if there is a strong favorite or if the lines are tight.
      Data: ${JSON.stringify(oddsData)}
    `;

    // Query GenAI with both the model name and prompt directly.
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
    });

    // Extract generated text from the .text property (not a method).
    return response.text || "Unable to generate analysis.";
  } catch (err) {
    console.error("Gemini Error:", err);
    return "Failed to analyze data with Gemini.";
  }
};

