import { Game, PlayerProp, OddsResponse, Bookmaker, Market, Outcome } from '../types';
import { useOdds } from '../hooks/useOdds';
import { useApiKey } from '../context/ApiKeyContext';
import { analyzeOddsWithGemini } from '../services/geminiService';

interface GameDetailProps {
  game: Game;
  onBack: () => void;
}

type Tab = 'TEAM' | 'PLAYER';

const GameDetail: React.FC<GameDetailProps> = ({ game, onBack }) => {
  const [activeTab, setActiveTab] = useState<Tab>('TEAM');
  const [analysis, setAnalysis] = useState<string | null>(null);
  const [analyzing, setAnalyzing] = useState(false);
  const [selectedBookmaker, setSelectedBookmaker] = useState<string>('draftkings');
  const { clearKey } = useApiKey();

  // Load team odds or player props based on active tab
  const marketsString = useMemo(() => {
    return activeTab === 'TEAM' 
      ? 'h2h,spreads,totals' 
      : 'player_points,player_assists,player_rebounds';
  }, [activeTab]);

  const { data, loading, error } = useOdds(game.id, marketsString);

  // Available bookmakers for the filter
  const availableBookmakers = useMemo(() => {
    if (!data || activeTab !== 'PLAYER') return [];
    return data.bookmakers.map(b => ({ key: b.key, title: b.title }));
  }, [data, activeTab]);

  // Grouped player props logic
  const groupedPlayerProps = useMemo<Record<string, PlayerProp[]>>(() => {
    if (activeTab !== 'PLAYER' || !data) return {};

    const groups: Record<string, PlayerProp[]> = {};

    data.bookmakers.forEach((bookie: Bookmaker) => {
      // Filter by selected bookmaker strictly
      if (bookie.key !== selectedBookmaker) return;

      bookie.markets.forEach((market: Market) => {
        // Consolidate Over/Under outcomes
        const marketOutcomesGrouped = market.outcomes.reduce((acc: any, outcome: Outcome) => {
          const playerName = outcome.description || 'Unknown';
          const line = outcome.point || 0;
          const key = `${playerName}_${line}_${market.key}`;

          if (!acc[key]) acc[key] = { playerName, marketKey: market.key, line };

          if (outcome.name === 'Over') acc[key].overPrice = outcome.price;
          if (outcome.name === 'Under') acc[key].underPrice = outcome.price;

          return acc;
        }, {});

        Object.keys(marketOutcomesGrouped).forEach((key) => {
          const prop = marketOutcomesGrouped[key] as PlayerProp;
          if (!groups[prop.playerName]) {
            groups[prop.playerName] = [];
          }
          groups[prop.playerName].push(prop);
        });
      });
    });

    // Sort within each player: Market Type then Line Value
    Object.keys(groups).forEach(player => {
      groups[player].sort((a, b) => {
        if (a.marketKey !== b.marketKey) return a.marketKey.localeCompare(b.marketKey);
        return a.line - b.line;
      });
    });

    return groups;
  }, [data, activeTab, selectedBookmaker]);

  const handleAnalyze = useCallback(async () => {
    if (!data) return;
    setAnalyzing(true);
    const result = await analyzeOddsWithGemini(data);
    setAnalysis(result);
    setAnalyzing(false);
