          onClick={() => setActiveTab('TEAM')}
          className={`tab-button ${activeTab === 'TEAM' ? 'active' : ''}`}
        >
          Team Odds
        </button>
        <button
          onClick={() => setActiveTab('PLAYER')}
          className={`tab-button ${activeTab === 'PLAYER' ? 'active' : ''}`}
        >
          Player Props
        </button>
      </div>

      <main style={{ padding: '16px' }}>
        {loading && <div style={{ fontSize: '11px', textTransform: 'uppercase' }}>Loading market data...</div>}

        {error && (
          <div style={{ display: 'flex', flexDirection: 'column', gap: '12px' }}>
            <div style={{ fontSize: '11px', textTransform: 'uppercase', color: 'red', fontWeight: 'bold' }}>Error: {error}</div>
            <button onClick={clearKey} style={{ backgroundColor: '#000', color: '#fff', alignSelf: 'flex-start' }}>Enter New API Key</button>
          </div>
        )}

        {!loading && !error && data && (
          <div style={{ display: 'flex', flexDirection: 'column', gap: '24px' }}>
            <section className="section-box">
              <h2 style={{ fontSize: '11px', fontWeight: 'bold', textTransform: 'uppercase', marginBottom: '8px', marginTop: 0 }}>Gemini Insight</h2>
              {analysis ? (
                <p style={{ fontSize: '11px', lineHeight: '1.5', fontStyle: 'italic', margin: 0 }}>"{analysis}"</p>
              ) : (
                <button 
                  onClick={handleAnalyze} 
                  disabled={analyzing}
                  style={{ fontSize: '10px' }}
                >
                  {analyzing ? 'Analyzing...' : 'Generate Analysis'}
                </button>
              )}
            </section>

            {activeTab === 'TEAM' ? (
              <div style={{ display: 'flex', flexDirection: 'column', gap: '16px' }}>
                {data.bookmakers.length === 0 ? (
                   <div style={{ fontSize: '11px', textTransform: 'uppercase', color: '#999' }}>No team odds available yet.</div>
                ) : (
                  data.bookmakers.slice(0, 3).map((bookie: Bookmaker) => (
                    <div key={bookie.key} style={{ border: '1px solid #eee', padding: '12px' }}>
                      <div style={{ fontSize: '10px', fontWeight: 'bold', textTransform: 'uppercase', marginBottom: '8px', borderBottom: '1px solid #f0f0f0', paddingBottom: '4px' }}>{bookie.title}</div>
                      <div style={{ display: 'flex', flexDirection: 'column', gap: '8px' }}>
                        {bookie.markets.map((market: Market) => (
                          <div key={market.key} style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', fontSize: '11px' }}>
                            <span style={{ textTransform: 'uppercase', color: '#666', fontFamily: 'monospace' }}>{market.key}:</span>
                            <div style={{ display: 'flex', gap: '8px' }}>
                              {market.outcomes.map((o: Outcome, i: number) => (
                                <span key={i} style={{ fontWeight: 'bold' }}>
                                  {o.name} {o.point !== undefined ? `(${o.point})` : ''} @ {o.price}
                                </span>
                              ))}
                            </div>
                          </div>
                        ))}
                      </div>
                    </div>
                  ))
                )}
              </div>
            ) : (
              <div style={{ display: 'flex', flexDirection: 'column' }}>
                <div style={{ marginBottom: '20px', display: 'flex', alignItems: 'center', gap: '12px' }}>
                  <label style={{ fontSize: '11px', fontWeight: '800', textTransform: 'uppercase' }}>Bookmaker:</label>
                  <select 
                    value={selectedBookmaker} 
                    onChange={(e) => setSelectedBookmaker(e.target.value)}
                  >
                    {availableBookmakers.map(b => (
                      <option key={b.key} value={b.key}>{b.title}</option>
                    ))}
                  </select>
                </div>

                {Object.keys(groupedPlayerProps).length === 0 ? (
                  <div style={{ fontSize: '11px', textTransform: 'uppercase', color: '#999' }}>Player props not available for {availableBookmakers.find(b => b.key === selectedBookmaker)?.title || selectedBookmaker}.</div>
                ) : (
                  Object.keys(groupedPlayerProps).map((playerName) => {
                    const props = groupedPlayerProps[playerName];
                    return (
                      <div key={playerName} className="player-group">
                        <div className="player-header">{playerName}</div>
                        <div style={{ display: 'flex', flexDirection: 'column' }}>
                          {props.map((prop, j) => (
                            <div key={j} className="prop-row">
                              <div className="prop-info">
                                <span className="prop-label">
                                  {prop.marketKey.replace('player_', '').replace('_', ' ')}
                                </span>
                                <span className="prop-line">{prop.line}</span>
                              </div>
                              <div className="odds-container">
                                <div className="odds-column">
                                  <span className="label-tiny">Over</span>
                                  <span className="odds-value">{prop.overPrice || '-'}</span>
                                </div>
                                <div className="odds-column">
                                  <span className="label-tiny">Under</span>
                                  <span className="odds-value">{prop.underPrice || '-'}</span>
                                </div>
                              </div>
                            </div>
                          ))}
                        </div>
                      </div>
                    );
                  })
                )}
              </div>
            )}
          </div>
        )}
      </main>
    </div>
  );
};

export default GameDetail;

import { Game, OddsResponse } from '../types';

const BASE_URL = 'https://api.the-odds-api.com/v4/sports/basketball_nba';

export const fetchNbaEvents = async (apiKey: string, signal?: AbortSignal): Promise<Game[]> => {
  const url = `${BASE_URL}/events?apiKey=${apiKey}`;
  // Log full path with redacted key
  console.log(`[API CALL] Fetching Events: ${url.replace(`apiKey=${apiKey}`, 'apiKey=REDACTED')}`);

  const response = await fetch(url, { signal });

  if (!response.ok) {
    const errorBody = await response.text().catch(() => 'No error body');
    console.error(`Fetch NBA Events Error [${response.status}]:`, errorBody);

    if (response.status === 401) throw new Error('Invalid API Key');
    if (response.status === 429) throw new Error('Rate limit exceeded');
    throw new Error(`Failed to fetch NBA events: ${response.status} ${response.statusText}`);
  }

  return response.json();
};

export const fetchOddsForGame = async (
  apiKey: string,
  eventId: string,
  markets: string = 'h2h,spreads,totals',
  signal?: AbortSignal
): Promise<OddsResponse> => {
  const url = `${BASE_URL}/events/${eventId}/odds?apiKey=${apiKey}&regions=us&markets=${markets}&oddsFormat=american`;
  // Log full path with redacted key
  console.log(`[API CALL] Fetching Game Odds: ${url.replace(`apiKey=${apiKey}`, 'apiKey=REDACTED')}`);

  const response = await fetch(url, { signal });

  if (!response.ok) {
    const errorBody = await response.text().catch(() => 'No error body');
    console.error(`Fetch Odds Error [${response.status}] for event ${eventId}:`, errorBody);

    if (response.status === 401) throw new Error('Invalid API Key');
    if (response.status === 422) throw new Error('Unprocessable Entity: Check if event ID or markets are valid for your subscription');
    if (response.status === 429) throw new Error('Rate limit exceeded');

    throw new Error(`Failed to fetch odds: ${response.status} ${response.statusText}`);
  }

  const data = await response.json();
  return data;
};

