import React, { useState, useMemo, useCallback } from 'react';
import { Game, OddsResponse, Bookmaker, Market, Outcome, PrimaryPlayerProp } from '../types';
import { useOdds } from '../hooks/useOdds';
import { useApiKey } from '../context/ApiKeyContext';
import { analyzeOddsWithGemini } from '../services/geminiService';

interface GameDetailProps {
  game: Game;
  onBack: () => void;
}

type Tab = 'TEAM' | 'PLAYER';

const GameDetail: React.FC<GameDetailProps> = ({ game, onBack }) => {
  const [activeTab, setActiveTab] = useState<Tab>('TEAM');
  const [analysis, setAnalysis] = useState<string | null>(null);
  const [analyzing, setAnalyzing] = useState(false);
  const [selectedBookmaker, setSelectedBookmaker] = useState<string>('draftkings');
  const { clearKey } = useApiKey();

  const marketsString = useMemo(() => {
    return activeTab === 'TEAM' 
      ? 'h2h,spreads,totals' 
      : 'player_points,player_assists,player_rebounds';
  }, [activeTab]);

  const { data, loading, error } = useOdds(game.id, marketsString);

  const availableBookmakers = useMemo(() => {
    if (!data || activeTab !== 'PLAYER') return [];
    return data.bookmakers.map(b => ({ key: b.key, title: b.title }));
  }, [data, activeTab]);

  /**
   * Primary Line Logic
   * 1. Group all available outcomes by Player + Market
   * 2. Determine which line has the highest frequency across all bookmakers
   * 3. Filter prices to show only those for that primary line
   */
  const primaryProps = useMemo<PrimaryPlayerProp[]>(() => {
    if (activeTab !== 'PLAYER' || !data) return [];

    const rawDataMap: Record<string, Record<number, PrimaryPlayerProp['offers']>> = {};

    // Step 1: Accumulate all offers from all bookmakers
    data.bookmakers.forEach((bookie: Bookmaker) => {
      bookie.markets.forEach((market: Market) => {
        // Group by player + market combination
        const outcomesByPlayer = market.outcomes.reduce((acc: any, outcome: Outcome) => {
          const playerName = outcome.description || 'Unknown';
          const line = outcome.point || 0;
          const key = `${playerName}|${market.key}`;

          if (!acc[key]) acc[key] = {};
          if (!acc[key][line]) acc[key][line] = { bookmakerKey: bookie.key, bookmakerTitle: bookie.title };

          if (outcome.name === 'Over') acc[key][line].overPrice = outcome.price;
          if (outcome.name === 'Under') acc[key][line].underPrice = outcome.price;

          return acc;
        }, {});

        Object.keys(outcomesByPlayer).forEach(playerMarketKey => {
          if (!rawDataMap[playerMarketKey]) rawDataMap[playerMarketKey] = {};

          Object.keys(outcomesByPlayer[playerMarketKey]).forEach(lineStr => {
            const line = parseFloat(lineStr);
            const offer = outcomesByPlayer[playerMarketKey][line];

            // Skip incomplete Over/Under pairs as per stability guards
            if (offer.overPrice === undefined || offer.underPrice === undefined) return;

            if (!rawDataMap[playerMarketKey][line]) rawDataMap[playerMarketKey][line] = [];
            rawDataMap[playerMarketKey][line].push(offer);
          });
        });
      });
    });

    // Step 2: Select the primary line per Player + Market
    const result: PrimaryPlayerProp[] = [];

    Object.keys(rawDataMap).forEach(playerMarketKey => {
      const linesMap = rawDataMap[playerMarketKey];
      const [playerName, marketKey] = playerMarketKey.split('|');

      const availableLines = Object.keys(linesMap).map(Number);
      if (availableLines.length === 0) return;

      // Primary line selection: Highest count, then lowest absolute line value
      let primaryLine = availableLines[0];
      let maxCount = -1;

      availableLines.forEach(line => {
        const count = linesMap[line].length;
        if (count > maxCount) {
          maxCount = count;
          primaryLine = line;
        } else if (count === maxCount) {
          if (Math.abs(line) < Math.abs(primaryLine)) {
            primaryLine = line;
          }
        }
      });

      result.push({
        playerName,
        marketKey,
        line: primaryLine,
        offers: linesMap[primaryLine]
      });
    });

    // Sort by Player Name, then Market Type
    return result.sort((a, b) => {
      if (a.playerName !== b.playerName) return a.playerName.localeCompare(b.playerName);
      return a.marketKey.localeCompare(b.marketKey);
    });
  }, [data, activeTab]);

  // Grouped results for UI rendering by Player
  const groupedByPlayer = useMemo(() => {
    const groups: Record<string, PrimaryPlayerProp[]> = {};
