/**
 * Pure helper function to select the primary line based on market consensus.
 * 1. Count how many bookmakers offer each line.
 * 2. Return the line with the highest count.
 * 3. Tie-break: lowest absolute value.
 */
const selectPrimaryLine = (
  playerMarketKey: string, 
  linesMap: Record<number, PlayerOffer[]>
): PrimaryPlayerProp | null => {
  const [playerName, marketKey] = playerMarketKey.split('|');
  const availableLines = Object.keys(linesMap).map(Number);

  if (availableLines.length === 0) return null;

  let primaryLine = availableLines[0];
  let maxCount = -1;

  availableLines.forEach(line => {
    const count = linesMap[line].length;
    if (count > maxCount) {
      maxCount = count;
      primaryLine = line;
    } else if (count === maxCount) {
      // Tied count: choose the lowest absolute line value
      if (Math.abs(line) < Math.abs(primaryLine)) {
        primaryLine = line;
      }
    }
  });

  return {
    playerName,
    marketKey,
    line: primaryLine,
    offers: linesMap[primaryLine]
  };
};

