import { Game, OddsResponse, EventMarket } from '../types';

const BASE_URL = 'https://api.the-odds-api.com/v4/sports/basketball_nba';
const ALLOWED_REGION = 'us';

export const fetchNbaEvents = async (apiKey: string, signal?: AbortSignal): Promise<Game[]> => {
  const url = `${BASE_URL}/events?apiKey=${apiKey}`;
  console.log(`[API CALL] Fetching Events: ${url.replace(`apiKey=${apiKey}`, 'apiKey=REDACTED')}`);

  const response = await fetch(url, { signal });
  if (!response.ok) throw new Error(`Events Fetch Failed: ${response.status}`);
  return response.json();
};

/**
 * Discovery: Fetch which markets are actually available for this game.
 * Cost: Low (doesn't include odds data)
 */
export const fetchAvailableMarkets = async (apiKey: string, eventId: string, signal?: AbortSignal): Promise<EventMarket[]> => {
  const url = `${BASE_URL}/events/${eventId}/markets?apiKey=${apiKey}&regions=${ALLOWED_REGION}`;
  console.log(`[API CALL] Discovery Markets: ${url.replace(`apiKey=${apiKey}`, 'apiKey=REDACTED')}`);

  const response = await fetch(url, { signal });
  if (!response.ok) throw new Error(`Market Discovery Failed: ${response.status}`);
  return response.json();
};

/**
 * Quota-Safe: Fetch odds for EXACTLY ONE market.
 * Cost: 1 unit per call.
 */
export const fetchOddsForMarket = async (
  apiKey: string,
  eventId: string,
  market: string,
  signal?: AbortSignal
): Promise<OddsResponse> => {
  // Strict enforcement: Only one market allowed per request.
  if (market.includes(',')) {
    throw new Error('Quota Safety Violation: Multiple markets requested in a single call.');
  }

  const url = `${BASE_URL}/events/${eventId}/odds?apiKey=${apiKey}&regions=${ALLOWED_REGION}&markets=${market}&oddsFormat=american`;
  console.log(`[API CALL] Fetching Market Odds [${market}]: ${url.replace(`apiKey=${apiKey}`, 'apiKey=REDACTED')}`);

  const response = await fetch(url, { signal });

  if (!response.ok) {
    if (response.status === 401) throw new Error('Invalid API Key');
    if (response.status === 429) throw new Error('Rate limit exceeded');
    throw new Error(`Odds Fetch Failed: ${response.status}`);
  }

  return response.json();
};

import React, { useState, useEffect, useMemo, useCallback } from 'react';
import { Game, OddsResponse, Bookmaker, Market, Outcome, PrimaryPlayerProp, PlayerOffer, EventMarket } from '../types';
import { fetchAvailableMarkets, fetchOddsForMarket } from '../api/oddsApi';
import { useApiKey } from '../context/ApiKeyContext';
import { analyzeOddsWithGemini } from '../services/geminiService';

interface GameDetailProps {
  game: Game;
  onBack: () => void;
}

type Tab = 'TEAM' | 'PLAYER';

const TEAM_MARKETS = ['h2h', 'spreads', 'totals'];
const PLAYER_MARKETS = ['player_points', 'player_assists', 'player_rebounds'];

const GameDetail: React.FC<GameDetailProps> = ({ game, onBack }) => {
  const { apiKey, clearKey } = useApiKey();
  const [activeTab, setActiveTab] = useState<Tab>('TEAM');
  const [selectedMarket, setSelectedMarket] = useState<string>('h2h');

  // State management
  const [availableMarkets, setAvailableMarkets] = useState<string[]>([]);
  const [marketCache, setMarketCache] = useState<Record<string, OddsResponse>>({});
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [selectedBookmaker, setSelectedBookmaker] = useState<string>('draftkings');

  // Analysis state
  const [analysis, setAnalysis] = useState<string | null>(null);
  const [analyzing, setAnalyzing] = useState(false);

  // 1. Discovery: Load available markets on mount
  useEffect(() => {
    if (!apiKey) return;
    const controller = new AbortController();

    setLoading(true);
    fetchAvailableMarkets(apiKey, game.id, controller.signal)
      .then(markets => {
        setAvailableMarkets(markets.map(m => m.key));
        setLoading(false);
      })
      .catch(err => {
        if (err.name !== 'AbortError') {
          setError('Failed to discover game markets.');
          setLoading(false);
        }
      });

    return () => controller.abort();
  }, [game.id, apiKey]);

  // 2. Lazy Loading: Load selected market odds if not in cache
  useEffect(() => {
    if (!apiKey || !selectedMarket || marketCache[selectedMarket] || !availableMarkets.includes(selectedMarket)) {
      return;
    }

    const controller = new AbortController();
