import React, { useState, useEffect, useMemo, useCallback } from 'react';
import { Game, OddsResponse, Bookmaker, Market, Outcome, PrimaryPlayerProp, PlayerOffer, EventMarket } from '../types';
import { fetchAvailableMarkets, fetchOddsForMarket } from '../api/oddsApi';
import { useApiKey } from '../context/ApiKeyContext';
import { analyzeOddsWithGemini } from '../services/geminiService';

interface GameDetailProps {
  game: Game;
  onBack: () => void;
}

type Tab = 'TEAM' | 'PLAYER';

const TEAM_MARKETS = ['h2h', 'spreads', 'totals'];
const PLAYER_MARKETS = ['player_points', 'player_assists', 'player_rebounds'];

const GameDetail: React.FC<GameDetailProps> = ({ game, onBack }) => {
  const { apiKey, clearKey } = useApiKey();
  const [activeTab, setActiveTab] = useState<Tab>('TEAM');
  const [selectedMarket, setSelectedMarket] = useState<string>('h2h');

  // State management
  const [availableMarkets, setAvailableMarkets] = useState<string[]>([]);
  const [marketCache, setMarketCache] = useState<Record<string, OddsResponse>>({});
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [selectedBookmaker, setSelectedBookmaker] = useState<string>('draftkings');

  // Analysis state
  const [analysis, setAnalysis] = useState<string | null>(null);
  const [analyzing, setAnalyzing] = useState(false);

  // Discovery: Load available markets on mount
  useEffect(() => {
    if (!apiKey) return;
    const controller = new AbortController();

    setLoading(true);
    fetchAvailableMarkets(apiKey, game.id, controller.signal)
      .then(markets => {
        const keys = markets.map(m => m.key);
        setAvailableMarkets(keys);
        setLoading(false);
        if (keys.length === 0) {
          setAvailableMarkets([...TEAM_MARKETS, ...PLAYER_MARKETS]);
        }
      })
      .catch(err => {
        if (err.name !== 'AbortError') {
          setAvailableMarkets([...TEAM_MARKETS, ...PLAYER_MARKETS]);
          setError(`Market Discovery Failed: ${err.message}. Using default markets.`);
          setLoading(false);
        }
      });

    return () => controller.abort();
  }, [game.id, apiKey]);

  // Lazy Loading: Load selected market odds if not in cache
  useEffect(() => {
    if (!apiKey || !selectedMarket || marketCache[selectedMarket] || !availableMarkets.includes(selectedMarket)) {
      return;
    }

    const controller = new AbortController();
    setLoading(true);
    setError(null);
    fetchOddsForMarket(apiKey, game.id, selectedMarket, controller.signal)
      .then(data => {
        setMarketCache(prev => ({ ...prev, [selectedMarket]: data }));
        setLoading(false);
      })
      .catch(err => {
        if (err.name !== 'AbortError') {
          setError(`Failed to fetch odds for ${selectedMarket}: ${err.message}`);
          setLoading(false);
        }
      });

    return () => controller.abort();
  }, [selectedMarket, availableMarkets, apiKey, game.id, marketCache]);

  // Clear analysis when market or tab changes to ensure relevance
  useEffect(() => {
    setAnalysis(null);
  }, [selectedMarket, activeTab]);

  // Handle tab switching - default to first available market in that group
  const handleTabSwitch = useCallback((tab: Tab) => {
    setActiveTab(tab);
    const defaults = tab === 'TEAM' ? TEAM_MARKETS : PLAYER_MARKETS;
    const firstAvailable = defaults.find(m => availableMarkets.includes(m));
    if (firstAvailable) setSelectedMarket(firstAvailable);
  }, [availableMarkets]);

  // Consensus Logic: Select primary line for the ACTIVE market
  const primaryProps = useMemo<PrimaryPlayerProp[]>(() => {
    const data = marketCache[selectedMarket];
    if (!data || !PLAYER_MARKETS.includes(selectedMarket)) return [];

    const rawDataMap: Record<string, Record<number, PlayerOffer[]>> = {};

    data.bookmakers.forEach((bookie) => {
      bookie.markets.forEach((market) => {
        market.outcomes.forEach((outcome) => {
          const playerName = outcome.description || 'Unknown';
          const line = outcome.point ?? 0;
          const key = `${playerName}|${market.key}`;

          if (!rawDataMap[key]) rawDataMap[key] = {};
          if (!rawDataMap[key][line]) rawDataMap[key][line] = [];

          const existingOffer = rawDataMap[key][line].find(o => o.bookmaker === bookie.key);
          if (existingOffer) {
            if (outcome.name === 'Over') existingOffer.overPrice = outcome.price;
            if (outcome.name === 'Under') existingOffer.underPrice = outcome.price;
          } else {
            rawDataMap[key][line].push({
              bookmaker: bookie.key,
              bookmakerTitle: bookie.title,
              overPrice: outcome.name === 'Over' ? outcome.price : undefined,
              underPrice: outcome.name === 'Under' ? outcome.price : undefined,
            });
          }
        });
      });
    });

    const results: PrimaryPlayerProp[] = [];
    Object.keys(rawDataMap).forEach(playerMarketKey => {
      const linesMap = rawDataMap[playerMarketKey];
      const availableLines = Object.keys(linesMap).map(Number);
      if (availableLines.length === 0) return;

      let primaryLine = availableLines[0];
      let maxCount = -1;
      availableLines.forEach(line => {
        const count = linesMap[line].filter(o => o.overPrice !== undefined && o.underPrice !== undefined).length;
        if (count > maxCount) {
          maxCount = count;
          primaryLine = line;
        } else if (count === maxCount && Math.abs(line) < Math.abs(primaryLine)) {
          primaryLine = line;
        }
      });

      const [playerName, marketKey] = playerMarketKey.split('|');
      results.push({
        playerName,
        marketKey,
        line: primaryLine,
        offers: linesMap[primaryLine].filter(o => o.overPrice !== undefined && o.underPrice !== undefined)
      });
    });

    return results.sort((a, b) => a.playerName.localeCompare(b.playerName));
  }, [marketCache, selectedMarket]);

  const currentBookmakers = useMemo(() => {
    const data = marketCache[selectedMarket];
    return data ? data.bookmakers.map(b => ({ key: b.key, title: b.title })) : [];
  }, [marketCache, selectedMarket]);

  const handleAnalyze = useCallback(async () => {
    const currentData = marketCache[selectedMarket];
    if (!currentData) return;
    setAnalyzing(true);

    const bookieTitle = currentBookmakers.find(b => b.key === selectedBookmaker)?.title || selectedBookmaker;

    // For players, send processed consensus data. For teams, send raw market data.
    const inputData = activeTab === 'PLAYER' ? primaryProps : currentData;

    const result = await analyzeOddsWithGemini(selectedMarket, bookieTitle, inputData);
    setAnalysis(result);
    setAnalyzing(false);
  }, [marketCache, selectedMarket, activeTab, primaryProps, selectedBookmaker, currentBookmakers]);

  return (
    <div style={{ display: 'flex', flexDirection: 'column', minHeight: '100vh', paddingBottom: '40px' }}>
      <header>
        <div style={{ display: 'flex', alignItems: 'center', gap: '16px', width: '100%' }}>
          <button onClick={onBack}>Back</button>
          <h1 style={{ margin: 0, fontSize: '14px', fontWeight: 'bold', textTransform: 'uppercase', flex: 1, whiteSpace: 'nowrap', overflow: 'hidden', textOverflow: 'ellipsis' }}>
            {game.away_team} @ {game.home_team}
          </h1>
          <button onClick={clearKey} style={{ border: '1px solid #ccc', color: '#999' }}>Reset</button>
        </div>
      </header>

      <div className="tabs">
        <button onClick={() => handleTabSwitch('TEAM')} className={`tab-button ${activeTab === 'TEAM' ? 'active' : ''}`}>Teams</button>
        <button onClick={() => handleTabSwitch('PLAYER')} className={`tab-button ${activeTab === 'PLAYER' ? 'active' : ''}`}>Players</button>
      </div>

      <main style={{ padding: '16px' }}>
        <div style={{ display: 'flex', gap: '8px', marginBottom: '20px', overflowX: 'auto', paddingBottom: '8px' }}>
          {(activeTab === 'TEAM' ? TEAM_MARKETS : PLAYER_MARKETS).map(m => (
            <button 
              key={m} 
              disabled={!availableMarkets.includes(m)}
              onClick={() => setSelectedMarket(m)}
              style={{ 
                flexShrink: 0,
                backgroundColor: selectedMarket === m ? '#000' : '#fff',
                color: selectedMarket === m ? '#fff' : '#000',
                opacity: availableMarkets.includes(m) ? 1 : 0.3,
                fontSize: '10px'
              }}
            >
              {m.replace('player_', '').replace('_', ' ')}
            </button>
          ))}
        </div>

        {loading && <div style={{ fontSize: '11px', textTransform: 'uppercase', marginBottom: '10px' }}>Processing request...</div>}
        {error && <div style={{ fontSize: '11px', color: 'red', marginBottom: '10px', padding: '8px', border: '1px solid red' }}>{error}</div>}

        {!loading && marketCache[selectedMarket] && (
          <div style={{ display: 'flex', flexDirection: 'column', gap: '20px' }}>
            <section className="section-box">
              <h2 style={{ fontSize: '11px', fontWeight: 'bold', textTransform: 'uppercase', marginBottom: '8px', marginTop: 0 }}>
                {activeTab === 'PLAYER' ? 'Parlay Builder' : 'Market Insight'} ({selectedMarket})
              </h2>
              {analysis ? (
                <div style={{ fontSize: '11px', lineHeight: '1.4', margin: 0, whiteSpace: 'pre-wrap' }}>{analysis}</div>
              ) : (
                <button onClick={handleAnalyze} disabled={analyzing} style={{ fontSize: '10px' }}>
                  {analyzing ? 'Analyzing...' : activeTab === 'PLAYER' ? 'Build Parlay' : 'Analyze Market'}
                </button>
              )}
            </section>

            <div style={{ display: 'flex', alignItems: 'center', gap: '8px', marginBottom: '12px' }}>
              <span style={{ fontSize: '11px', fontWeight: '800', textTransform: 'uppercase' }}>Bookmaker:</span>
              <select value={selectedBookmaker} onChange={(e) => setSelectedBookmaker(e.target.value)} style={{ fontSize: '11px' }}>
                {currentBookmakers.map(b => <option key={b.key} value={b.key}>{b.title}</option>)}
              </select>
            </div>

            {activeTab === 'TEAM' ? (
              <div style={{ display: 'flex', flexDirection: 'column', gap: '12px' }}>
                {marketCache[selectedMarket]?.bookmakers.slice(0, 5).map(b => (
                  <div key={b.key} style={{ border: '1px solid #eee', padding: '10px' }}>
                    <div style={{ fontSize: '10px', fontWeight: 'bold', textTransform: 'uppercase', marginBottom: '4px' }}>{b.title}</div>
                    {b.markets[0]?.outcomes.map((o, i) => (
                      <div key={i} style={{ display: 'flex', justifyContent: 'space-between', fontSize: '12px', padding: '2px 0' }}>
                        <span>{o.name} {o.point !== undefined ? `(${o.point})` : ''}</span>
                        <span style={{ fontWeight: 'bold' }}>{o.price}</span>
                      </div>
                    ))}
                  </div>
                ))}
              </div>
            ) : (
              <div style={{ display: 'flex', flexDirection: 'column' }}>
                {primaryProps.length === 0 ? (
                  <div style={{ fontSize: '11px', textTransform: 'uppercase', color: '#999' }}>No consensus found for {selectedMarket}.</div>
                ) : (
                  primaryProps.map(prop => {
                    const offer = prop.offers.find(o => o.bookmaker === selectedBookmaker);
                    return (
                      <div key={prop.playerName} className="player-group">
                        <div className="player-header">{prop.playerName}</div>
                        <div className="prop-row">
                          <div className="prop-info">
                            <span className="prop-label">{prop.marketKey.split('_')[1]}</span>
                            <span className="prop-line">{prop.line}</span>
                          </div>
                          <div className="odds-container">
                            {offer ? (
                              <>
                                <div className="odds-column">
                                  <span className="label-tiny">Over</span>
                                  <span className="odds-value">{offer.overPrice}</span>
                                </div>
                                <div className="odds-column">
                                  <span className="label-tiny">Under</span>
                                  <span className="odds-value">{offer.underPrice}</span>
                                </div>
                              </>
                            ) : (
                              <div style={{ fontSize: '9px', color: '#999', textTransform: 'uppercase', textAlign: 'right' }}>
                                No Line at {selectedBookmaker}
                              </div>
                            )}
                          </div>
                        </div>
                      </div>
                    );
                  })
                )}
              </div>
            )}
          </div>
        )}
      </main>
    </div>
  );
};

export default GameDetail;

import { GoogleGenAI, Type } from "@google/genai";

export interface ParlayPrediction {
  playerName: string;
  market: string;
  line: number;
  prediction: "MORE" | "LESS";
  reason: string;
}

/**
 * Analyzes NBA odds data using Gemini 3 Flash.
 * Returns a JSON structured parlay analysis for player props.
 */
export const analyzeOddsWithGemini = async (
  marketName: string,
  selectedBookmakerTitle: string,
  data: any
): Promise<ParlayPrediction[] | string> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  try {
    const isPlayerMarket = marketName.startsWith('player_');

    if (isPlayerMarket) {
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: `
          You are a professional NBA betting analyst. Task: Build a parlay for the ${marketName} market.
          Analyze the provided market consensus and the data from bookmaker "${selectedBookmakerTitle}".

          Data: ${JSON.stringify(data)}

          For EVERY player, predict if they will go MORE (Over) or LESS (Under) the line.
          Include a short reasoning based on the bookmaker odds and consensus.
        `,
        config: {
          responseMimeType: "application/json",
          responseSchema: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                playerName: { type: Type.STRING },
                market: { type: Type.STRING },
                line: { type: Type.NUMBER },
                prediction: { type: Type.STRING, description: "Must be 'MORE' or 'LESS'" },
                reason: { type: Type.STRING }
              },
              required: ["playerName", "market", "line", "prediction", "reason"]
            }
          }
        }
      });

      return JSON.parse(response.text || "[]");
    } else {
      // Team analysis remains as text for now
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: `Analyze these NBA team odds for ${marketName}: ${JSON.stringify(data)}. Summarize in 3 sentences.`,
      });
      return response.text || "No summary available.";
    }
  } catch (err) {
    console.error("Gemini Error:", err);
    return "Analysis failed.";
  }
};

