    return results.sort((a, b) => a.playerName.localeCompare(b.playerName));
  }, [marketCache, selectedMarket]);

  const currentBookmakers = useMemo(() => {
    const data = marketCache[selectedMarket];
    return data ? data.bookmakers.map(b => ({ key: b.key, title: b.title })) : [];
  }, [marketCache, selectedMarket]);

  const handleAnalyze = useCallback(async () => {
    const currentData = marketCache[selectedMarket];
    if (!currentData) return;
    setAnalyzing(true);
    const bookieTitle = currentBookmakers.find(b => b.key === selectedBookmaker)?.title || selectedBookmaker;
    const result = await analyzeOddsWithGemini(selectedMarket, bookieTitle, primaryProps);
    setParlay(result);
    setAnalyzing(false);
  }, [marketCache, selectedMarket, primaryProps, selectedBookmaker, currentBookmakers]);

  const renderMarketLabel = (key: string) => key.replace('player_', '').replace('_', ' ').toUpperCase();

  return (
    <div style={{ display: 'flex', flexDirection: 'column', minHeight: '100vh', paddingBottom: '40px' }}>
      <header>
        <button onClick={onBack}>Back</button>
        <h1 style={{ margin: 0, fontSize: '13px', fontWeight: '900', textTransform: 'uppercase', flex: 1, textAlign: 'center' }}>
          {game.away_team} @ {game.home_team}
        </h1>
        <button onClick={clearKey} style={{ border: 'none', color: '#999', padding: 0 }}>Reset</button>
      </header>

      <main style={{ padding: '20px' }}>
        <div style={{ display: 'flex', gap: '8px', marginBottom: '20px', overflowX: 'auto', paddingBottom: '4px' }}>
          {availableMarkets.map(m => (
            <button 
              key={m} 
              onClick={() => setSelectedMarket(m)}
              style={{ 
                borderWidth: '2px',
                backgroundColor: selectedMarket === m ? '#000' : '#fff',
                color: selectedMarket === m ? '#fff' : '#000',
                fontSize: '10px'
              }}
            >
              {m.replace('player_', '').replace('_', ' ')}
            </button>
          ))}
        </div>

        {loading && <div className="label-tiny" style={{ marginBottom: '16px' }}>Requesting Feed...</div>}
        {error && <div className="label-tiny" style={{ color: 'red', marginBottom: '16px' }}>{error}</div>}

        {!loading && marketCache[selectedMarket] && (
          <div style={{ display: 'flex', flexDirection: 'column', gap: '24px' }}>
            {/* Action Bar */}
            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
               <div style={{ display: 'flex', alignItems: 'center', gap: '8px' }}>
                <span className="label-tiny">Bookmaker</span>
                <select value={selectedBookmaker} onChange={(e) => setSelectedBookmaker(e.target.value)}>
                  {currentBookmakers.map(b => <option key={b.key} value={b.key}>{b.title}</option>)}
                </select>
              </div>
              <button onClick={handleAnalyze} disabled={analyzing} style={{ backgroundColor: '#000', color: '#fff' }}>
                {analyzing ? '...' : parlay ? 'Refresh Parlay' : 'Build Parlay'}
              </button>
            </div>

            <div style={{ display: 'flex', flexDirection: 'column' }}>
              {parlay && (
                <div className="ai-badge" style={{ alignSelf: 'flex-start' }}>
                  Parlay Builder AI Results
                </div>
              )}

              {primaryProps.length === 0 ? (
                <div className="no-line">No players found for this market.</div>
              ) : (
                <div style={{ 
                  display: 'grid', 
                  gridTemplateColumns: '1fr 1fr', 
                  gap: '16px' 
                }}>
                  {primaryProps.map(prop => {
                    const offer = prop.offers.find(o => o.bookmaker === selectedBookmaker);
                    const bookieName = currentBookmakers.find(b => b.key === selectedBookmaker)?.title || selectedBookmaker;
                    const prediction = parlay?.find(p => p.playerName === prop.playerName);

                    return (
                      <div key={prop.playerName} className="player-group">
                        <div className="player-header">{prop.playerName}</div>

                        <div className="prop-body">
                          {prediction ? (
                            <div style={{ display: 'flex', justifyContent: 'space-between', gap: '8px' }}>
                              <div style={{ display: 'flex', flexDirection: 'column', flexShrink: 0 }}>
                                <span className="parlay-prediction" style={{ marginTop: 0, marginBottom: '4px' }}>{prediction.prediction}</span>
                                <span className="prop-line">{prop.line}</span>
                                <span className="prop-label">{renderMarketLabel(prop.marketKey)}</span>
                              </div>
                              <div className="parlay-reason" style={{ marginTop: 0, borderTop: 'none', textAlign: 'left', paddingLeft: '4px', flex: 1 }}>
                                {prediction.reason}
                              </div>
                            </div>
                          ) : (
                            <div style={{ display: 'flex', flexDirection: 'column', gap: '12px' }}>
                              <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start' }}>
                                <div style={{ display: 'flex', flexDirection: 'column' }}>
                                  <span className="prop-line">{prop.line}</span>
                                  <span className="prop-label">{renderMarketLabel(prop.marketKey)}</span>
                                </div>
                                <div className="odds-container" style={{ flexDirection: 'column', gap: '4px' }}>
                                  {offer ? (
                                    <>
                                      <div className="odds-column">
                                        <span className="label-tiny">OVER</span>
                                        <span className="odds-value" style={{ fontSize: '12px' }}>{offer.overPrice}</span>
                                      </div>
                                      <div className="odds-column">
                                        <span className="label-tiny">UNDER</span>
                                        <span className="odds-value" style={{ fontSize: '12px' }}>{offer.underPrice}</span>
                                      </div>
                                    </>
                                  ) : (
                                    <div className="no-line">No line</div>
                                  )}
                                </div>
                              </div>
                            </div>
                          )}
                        </div>
                      </div>
                    );
                  })}
                </div>
              )}
            </div>
          </div>
        )}
      </main>
    </div>
  );
};

