                                    </div>
                                  </>
                                ) : (
                                  <div style={{ fontSize: '11px', color: 'var(--secondary-text)', fontWeight: 600 }}>Market unavailable</div>
                                )}
                              </div>
                            )}
                          </div>

                          {/* 3. Miss Risk (Secondary, bottom row) */}
                          <div className="emr-row">
                            {offer ? (
                              <span className={`risk-tag ${riskClass}`}>
                                {formatRiskLevel(emr.level)} ({emr.value}%)
                              </span>
                            ) : (
                              <span className="risk-tag risk-disabled">
                                Waiting for market line
                              </span>
                            )}
                          </div>
                        </div>
                      </div>
                    );
                  })}
                </div>
              )}
            </div>
          </div>
        )}
      </main>
    </div>
  );
};

