/**
 * Deterministic Analysis Engine
 * Infers market-implied scripts and structural insights from Odds API data.
 * Adheres to strict non-redundancy and performance constraints (no external LLM calls).
 */
export const analyzeMarketStructure = (
  props: PrimaryPlayerProp[],
  selectedBookmaker: string
): MarketAnalysis => {
  const players: PlayerAnalysis[] = props.map(prop => {
    const offer = prop.offers.find(o => o.bookmaker === selectedBookmaker);

    // 1. Deterministic More/Less based on Implied Probability
    let prediction: "MORE" | "LESS" = "MORE";
    if (offer?.overPrice && offer?.underPrice) {
      const getProb = (o: number) => o < 0 ? Math.abs(o) / (Math.abs(o) + 100) : 100 / (o + 100);
      prediction = getProb(offer.overPrice) > getProb(offer.underPrice) ? "MORE" : "LESS";
    }

    // 2. Structural Insights (Rule-based, Non-Redundant)
    const bullets: string[] = [];

    // Insight Category: Role Sensitivity & Usage
    if (prop.parlayRole === 'Volatile') {
      bullets.push("Pricing reflects reliance on usage spikes rather than volume stability");
    } else if (prop.parlayRole === 'Anchor') {
      bullets.push("Market implies outcome depends on primary role continuity");
    } else {
      bullets.push("Outcome reflects expected redistribution of team scoring load");
    }

    // Insight Category: Line Fragility & Game Flow
    if (prop.line % 1 !== 0) {
      bullets.push("Half-step margins imply sensitivity to game flow and rotations");
    } else {
      bullets.push("Line placement suggests hidden fragility masked by volume consensus");
    }

    // Insight Category: Market Confidence Interpretation
    if (prop.consensusStrength === 'Low') {
      bullets.push("Wide disagreement reflects variance in projected usage density");
    } else {
      bullets.push("Clustered pricing behavior suggests low structural volatility");
    }

    return {
      playerName: prop.playerName,
      prediction,
      bullets: bullets.slice(0, 2) // Maintain 2 bullets for card clarity
    };
  });

  // 3. Game-Level Market-Implied Script (Summarized from collective pricing)
  const volatileCount = props.filter(p => p.parlayRole === 'Volatile').length;
  const gameScript = [
    volatileCount > 4 
      ? "Market pricing expects scoring to concentrate among primary creators" 
      : "Pricing behavior reflects a balanced redistribution of scoring load",
    "Assist and rebound props imply a controlled half-court possession pace",
    "Line structures suggest high sensitivity to late-game competitiveness"
  ];

  return { gameScript, players };
};

