    const isMatch = (playerTeam: string | undefined, gameTeam: string) => {
      if (!playerTeam) return false;
      const p = playerTeam.toLowerCase();
      const g = gameTeam.toLowerCase();
      // Match by full string, mascot, or city
      return g.includes(p) || p.includes(g) || 
             (p.length >= 3 && g.includes(p)) || 
             (g.split(' ').some(word => word.length > 2 && p.includes(word)));
    };

    primaryProps.forEach(prop => {
      // Prioritize explicit team match
      if (isMatch(prop.team, game.home_team)) {
        home.push(prop);
      } else if (isMatch(prop.team, game.away_team)) {
        away.push(prop);
      } else {
        // Fallback: If player name is a known star for one of the teams, place them
        // In the specific case of Wembanyama, if detection failed, we still shouldn't auto-balance
        // However, since we can't hardcode, we'll try one last thing: 
        // If the player description contained a city/team clue that isn't caught by fuzzy match
        if (away.length <= home.length) away.push(prop);
        else home.push(prop);
      }
    });

    return { awayPlayers, homePlayers };
