                      <span className="odds-value">{offer.overPrice}</span>
                    </div>
                    <div style={{ display: 'flex', flexDirection: 'column', alignItems: 'center' }}>
                      <span className="label-tiny">UNDER</span>
                      <span className="odds-value">{offer.underPrice}</span>
                    </div>
                  </>
                ) : (
                  <div style={{ fontSize: '7.5px', color: '#9ca3af', fontWeight: 600 }}>UNAVAILABLE</div>
                )}
              </div>
            )}
          </div>

          <div style={{ display: 'flex', flexDirection: 'column', gap: '2px', marginBottom: '4px' }}>
            <div 
              className="consensus-indicator" 
              title="Consensus reflects how closely sportsbooks agree on this line — not whether it will win or lose."
              style={{ 
                fontSize: '8px', 
                color: '#9ca3af', 
                fontWeight: 700, 
                textTransform: 'uppercase',
                letterSpacing: '0.3px',
                cursor: 'help'
              }}
            >
              Consensus: {prop.consensusStrength}
            </div>
            <div 
              className="parlay-role-label"
              style={{ 
                fontSize: '8px', 
                color: '#9ca3af', 
                fontWeight: 800, 
                textTransform: 'uppercase',
                letterSpacing: '0.3px',
                opacity: 0.8
              }}
            >
              Role: {prop.parlayRole}
            </div>
          </div>

          <div className="emr-row">
            {offer ? (
              <span className={`risk-tag ${riskClass}`}>
                {formatRiskLevel(emr.level)} ({emr.value}%)
              </span>
            ) : (
              <span className="risk-tag risk-disabled">No Context</span>
            )}
          </div>
        </div>
      </div>
    );
  };

  return (
    <div style={{ display: 'flex', flexDirection: 'column', minHeight: '100vh', paddingBottom: '32px' }}>
      <header>
        <button onClick={onBack} style={{ fontWeight: '900' }}>BACK</button>
        <h1 style={{ margin: 0, fontSize: '11px', fontWeight: '900', textTransform: 'uppercase', flex: 1, textAlign: 'center' }}>
          {game.away_team} <span style={{ color: '#9ca3af' }}>@</span> {game.home_team}
        </h1>
        <button onClick={clearKey} style={{ border: 'none', color: '#9ca3af', boxShadow: 'none', fontWeight: '900' }}>LOGOUT</button>
      </header>

      <main>
        <div className="tab-container">
          {availableMarkets.map(m => (
            <button 
              key={m} 
              onClick={() => setSelectedMarket(m)}
              className={`tab-item ${selectedMarket === m ? 'active' : ''}`}
            >
              {renderMarketLabelClean(m)}
            </button>
          ))}
        </div>

        {!loading && (
          <div style={{ display: 'flex', flexDirection: 'column', gap: '6px' }}>
            {analysis && (
              <div className="volatility-context" style={{ textAlign: 'left', padding: '12px', marginBottom: '12px' }}>
                <div className="label-tiny" style={{ marginBottom: '8px', color: 'var(--primary-text)', fontWeight: 900 }}>Market-Implied Script</div>
                <ul style={{ margin: 0, paddingLeft: '16px', fontSize: '10px', color: '#374151', fontWeight: 600 }}>
                  {analysis.gameScript.map((s, i) => <li key={i} style={{ marginBottom: '4px' }}>{s}</li>)}
                </ul>
              </div>
            )}

            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '12px', padding: '0 8px' }}>
               <div style={{ display: 'flex', alignItems: 'center', gap: '4px' }}>
                <span className="label-tiny">Sportsbook</span>
                <select value={selectedBookmaker} onChange={(e) => setSelectedBookmaker(e.target.value)} style={{ fontSize: '9px', fontWeight: '700', borderRadius: '4px', padding: '2px' }}>
                  {currentBookmakers.map(b => <option key={b.key} value={b.key}>{b.title}</option>)}
                </select>
              </div>
              <button 
                onClick={handleAnalyze} 
                disabled={analyzing} 
                className={analyzing ? "" : "btn-primary-gradient"}
                style={{ fontSize: '9px', fontWeight: 900 }}
              >
                {analyzing ? 'STRUCTURAL SCAN...' : 'BUILD MARKET ANALYSIS'}
              </button>
            </div>

            {loading && <div className="label-tiny" style={{ textAlign: 'center' }}>Updating Feed...</div>}
            {error && <div className="label-tiny" style={{ color: '#dc2626', textAlign: 'center' }}>{error}</div>}

            <div className="team-group-grid">
              <div className="team-column">
                <div className="team-label">AWAY — <span>{game.away_team}</span></div>
                {awayPlayers.length === 0 && !loading && (
                   <div className="label-tiny" style={{ textAlign: 'center', padding: '10px' }}>No Props Found</div>
                )}
                {awayPlayers.map(renderPlayerCard)}
              </div>

              <div className="team-column">
                <div className="team-label">HOME — <span>{game.home_team}</span></div>
                {homePlayers.length === 0 && !loading && (
                   <div className="label-tiny" style={{ textAlign: 'center', padding: '10px' }}>No Props Found</div>
                )}
                {homePlayers.map(renderPlayerCard)}
              </div>
            </div>
          </div>
        )}
      </main>
    </div>
  );
};

export default GameDetail;

import React, { useState, useEffect, useMemo, useCallback } from 'react';
import { Game, OddsResponse, Bookmaker, Market, Outcome, PrimaryPlayerProp, PlayerOffer, EventMarket, MarketAnalysis } from '../types';
import { fetchAvailableMarkets, fetchOddsForMarket } from '../api/oddsApi';
import { useApiKey } from '../context/ApiKeyContext';
import { analyzeMarketStructure } from '../services/geminiService';
import { calculateEMR } from '../utils/emrCalculator';
import { evaluateParlayRole } from '../utils/parlayFit';

interface GameDetailProps {
  game: Game;
  onBack: () => void;
}

const PLAYER_MARKETS = ['player_points', 'player_assists', 'player_rebounds', 'player_blocks', 'player_steals', 'player_threes'];

const GameDetail: React.FC<GameDetailProps> = ({ game, onBack }) => {
  const { apiKey, clearKey } = useApiKey();
  const [selectedMarket, setSelectedMarket] = useState<string>('player_points');

  const [availableMarkets, setAvailableMarkets] = useState<string[]>([]);
  const [marketCache, setMarketCache] = useState<Record<string, OddsResponse>>({});
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [selectedBookmaker, setSelectedBookmaker] = useState<string>('draftkings');

  const [analysis, setAnalysis] = useState<MarketAnalysis | null>(null);
  const [analyzing, setAnalyzing] = useState(false);

  useEffect(() => {
    if (!apiKey) return;
    const controller = new AbortController();
    setLoading(true);
    fetchAvailableMarkets(apiKey, game.id, controller.signal)
      .then(markets => {
        const playerKeys = Array.isArray(markets) 
          ? markets.map(m => m.key).filter(k => k.startsWith('player_'))
          : [];
        setAvailableMarkets(playerKeys.length > 0 ? playerKeys : PLAYER_MARKETS);
        setLoading(false);
      })
      .catch(err => {
        if (err.name !== 'AbortError') {
          setAvailableMarkets(PLAYER_MARKETS);
          setLoading(false);
        }
      });
    return () => controller.abort();
  }, [game.id, apiKey]);

  useEffect(() => {
    if (!apiKey || !selectedMarket || marketCache[selectedMarket]) return;
    const controller = new AbortController();
    setLoading(true);
    setError(null);
    fetchOddsForMarket(apiKey, game.id, selectedMarket, controller.signal)
      .then(data => {
        setMarketCache(prev => ({ ...prev, [selectedMarket]: data }));
        setLoading(false);
      })
      .catch(err => {
        if (err.name !== 'AbortError') {
          setError(`Market details currently unavailable.`);
          setLoading(false);
        }
      });
    return () => controller.abort();
  }, [selectedMarket, apiKey, game.id, marketCache]);

  useEffect(() => {
    setAnalysis(null);
  }, [selectedMarket, selectedBookmaker]);

  const primaryProps = useMemo<PrimaryPlayerProp[]>(() => {
    const data = marketCache[selectedMarket];
    if (!data) return [];

    const rawDataMap: Record<string, { team?: string; lines: Record<number, PlayerOffer[]> }> = {};
    data.bookmakers.forEach((bookie) => {
      bookie.markets.forEach((market) => {
        market.outcomes.forEach((outcome) => {
          let playerName = (outcome.description || '').trim();
          if (!playerName || playerName === 'Unknown') return;

          let extractedTeam = outcome.team;
          const teamMatch = playerName.match(/\(([^)]+)\)$/);
          if (teamMatch && !extractedTeam) {
            extractedTeam = teamMatch[1];
            playerName = playerName.replace(/\([^)]+\)$/, '').trim();
          }

          const line = outcome.point ?? 0;
          const key = `${playerName}|${market.key}`;

          if (!rawDataMap[key]) {
            rawDataMap[key] = { team: extractedTeam, lines: {} };
          } else if (!rawDataMap[key].team && extractedTeam) {
            rawDataMap[key].team = extractedTeam;
          }

          if (!rawDataMap[key].lines[line]) {
            rawDataMap[key].lines[line] = [];
          }

          const existing = rawDataMap[key].lines[line].find(o => o.bookmaker === bookie.key);
          if (existing) {
            if (outcome.name === 'Over') existing.overPrice = outcome.price;
            if (outcome.name === 'Under') existing.underPrice = outcome.price;
          } else {
            rawDataMap[key].lines[line].push({
              bookmaker: bookie.key,
              bookmakerTitle: bookie.title,
              overPrice: outcome.name === 'Over' ? outcome.price : undefined,
              underPrice: outcome.name === 'Under' ? outcome.price : undefined,
            });
          }
        });
      });
    });

    const results: PrimaryPlayerProp[] = [];
    Object.keys(rawDataMap).forEach(key => {
      const { team, lines: linesMap } = rawDataMap[key];
      const lines = Object.keys(linesMap).map(Number);
      if (lines.length === 0) return;

      let primaryLine = lines[0];
      let maxCount = -1;
      lines.forEach(line => {
        const count = linesMap[line].filter(o => o.overPrice && o.underPrice).length;
        if (count > maxCount) { maxCount = count; primaryLine = line; }
      });
      const [playerName, marketKey] = key.split('|');
      const offersAtPrimary = linesMap[primaryLine];

      let consensusStrength: 'Low' | 'Medium' | 'High' = 'Low';
      const bookCount = offersAtPrimary.length;
      let avgOverPrice = -110;

      if (bookCount >= 2) {
        const overPrices = offersAtPrimary.map(o => o.overPrice).filter((p): p is number => p !== undefined);
        avgOverPrice = overPrices.reduce((a, b) => a + b, 0) / overPrices.length;
        const overFavoredCount = overPrices.filter(p => p < 0).length;
        const underFavoredCount = overPrices.filter(p => p > 0).length;
        const juiceAligned = overFavoredCount === overPrices.length || underFavoredCount === overPrices.length;
        consensusStrength = bookCount >= 3 ? (juiceAligned ? 'High' : 'Medium') : 'Medium';
      }

      const parlayRole = evaluateParlayRole(primaryLine, marketKey, consensusStrength, avgOverPrice);
      results.push({ playerName, marketKey, line: primaryLine, team, offers: offersAtPrimary, consensusStrength, parlayRole });
    });
    return results.sort((a, b) => a.playerName.localeCompare(b.playerName));
  }, [marketCache, selectedMarket]);

  const { awayPlayers, homePlayers } = useMemo(() => {
    const awayList: PrimaryPlayerProp[] = [];
    const homeList: PrimaryPlayerProp[] = [];

    const isMatch = (playerTeam: string | undefined, gameTeam: string) => {
      if (!playerTeam) return false;
      const p = playerTeam.toLowerCase();
      const g = gameTeam.toLowerCase();

      // Exact or partial name match
      if (g.includes(p) || p.includes(g)) return true;

      // Mascot/City word match
      const gWords = g.split(' ');
      if (gWords.some(word => word.length > 3 && p.includes(word.toLowerCase()))) return true;

      // Common Abbreviation mappings
      const abbreviations: Record<string, string[]> = {
        'okc': ['oklahoma', 'thunder'],
        'sas': ['san antonio', 'spurs'],
        'lal': ['lakers'],
        'lac': ['clippers'],
        'gsw': ['golden state', 'warriors'],
        'bos': ['celtics'],
        'phi': ['76ers', 'sixers']
      };

      if (abbreviations[p]) {
        return abbreviations[p].some(name => g.includes(name));
      }

      return false;
    };

    primaryProps.forEach(prop => {
      if (isMatch(prop.team, game.home_team)) {
        homeList.push(prop);
      } else if (isMatch(prop.team, game.away_team)) {
        awayList.push(prop);
      } else {
        // Strict fallback: avoid column auto-balancing if team data exists but doesn't match
        // Put in left column by default only if team is missing
        if (!prop.team) awayList.push(prop);
        else awayList.push(prop); // Still away if unsure
      }
    });

    return { awayPlayers: awayList, homePlayers: homeList };
  }, [primaryProps, game]);

  const currentBookmakers = useMemo(() => {
    const data = marketCache[selectedMarket];
    return data ? data.bookmakers.map(b => ({ key: b.key, title: b.title })) : [];
  }, [marketCache, selectedMarket]);

  const handleAnalyze = useCallback(() => {
    setAnalyzing(true);
    setTimeout(() => {
      const result = analyzeMarketStructure(primaryProps, selectedBookmaker);
      setAnalysis(result);
      setAnalyzing(false);
    }, 400);
  }, [primaryProps, selectedBookmaker]);

  const renderMarketLabel = (key: string) => key.replace('player_', '').replace('_', ' ').toUpperCase();
  const renderMarketLabelClean = (key: string) => {
    const words = key.replace('player_', '').split('_');
    return words.map(w => w.charAt(0).toUpperCase() + w.slice(1)).join(' ');
  };

  const renderPlayerCard = (prop: PrimaryPlayerProp) => {
    const offer = prop.offers.find(o => o.bookmaker === selectedBookmaker);
    const playerAnalysis = analysis?.players.find(p => p.playerName === prop.playerName);
    const emr = calculateEMR(prop, selectedBookmaker);

    const riskClass = 
      emr.level === 'Lower Miss Risk' ? 'risk-lower' : 
      emr.level === 'Moderate Miss Risk' ? 'risk-moderate' : 
      emr.level === 'Elevated Miss Risk' ? 'risk-elevated' : 'risk-high';

    return (
      <div key={prop.playerName + prop.marketKey} className="card player-group">
        <div className="player-header">{prop.playerName}</div>
        <div className="prop-body">
          <span className="prop-line">{prop.line}</span>
          <span className="prop-label">{renderMarketLabel(prop.marketKey)}</span>
          <div className="market-section" style={{ paddingBottom: playerAnalysis ? '8px' : '10px' }}>
            {playerAnalysis ? (
              <div style={{ display: 'flex', flexDirection: 'column', alignItems: 'center', gap: '6px', width: '100%' }}>
                <div className={`prediction-badge ${playerAnalysis.prediction === 'MORE' ? 'prediction-more' : 'prediction-less'}`}>
                  {playerAnalysis.prediction}
                </div>
                <div style={{ width: '100%', textAlign: 'left', padding: '0 8px' }}>
                  <ul style={{ margin: 0, paddingLeft: '12px', fontSize: '8.5px', color: '#4b5563', lineHeight: 1.4, fontWeight: 500 }}>
                    {playerAnalysis.bullets.map((b, i) => <li key={i}>{b}</li>)}
                  </ul>
                </div>
              </div>
            ) : (
              <div style={{ display: 'flex', gap: '8px' }}>
                {offer ? (
                  <>
                    <div style={{ display: 'flex', flexDirection: 'column', alignItems: 'center' }}>
                      <span className="label-tiny">OVER</span>
                      <span className="odds-value">{offer.overPrice}</span>
                    </div>
                    <div style={{ display: 'flex', flexDirection: 'column', alignItems: 'center' }}>
                      <span className="label-tiny">UNDER</span>
                      <span className="odds-value">{offer.underPrice}</span>
                    </div>
                  </>
                ) : (
                  <div style={{ fontSize: '7.5px', color: '#9ca3af', fontWeight: 600 }}>UNAVAILABLE</div>
                )}
              </div>
            )}
          </div>
          <div style={{ display: 'flex', flexDirection: 'column', gap: '2px', marginBottom: '4px' }}>
            <div className="consensus-indicator" style={{ fontSize: '8px', color: '#9ca3af', fontWeight: 700, textTransform: 'uppercase' }}>
              Consensus: {prop.consensusStrength}
            </div>
            <div className="parlay-role-label" style={{ fontSize: '8px', color: '#9ca3af', fontWeight: 800, textTransform: 'uppercase', opacity: 0.8 }}>
              Role: {prop.parlayRole}
            </div>
          </div>
          <div className="emr-row">
            {offer ? (
              <span className={`risk-tag ${riskClass}`}>
                {emr.level.charAt(0).toUpperCase() + emr.level.slice(1).toLowerCase()} ({emr.value}%)
              </span>
            ) : (
              <span className="risk-tag risk-disabled">No Context</span>
            )}
          </div>
        </div>
      </div>
    );
  };

  return (
    <div style={{ display: 'flex', flexDirection: 'column', minHeight: '100vh', paddingBottom: '32px' }}>
      <header>
        <button onClick={onBack} style={{ fontWeight: '900' }}>BACK</button>
        <h1 style={{ margin: 0, fontSize: '11px', fontWeight: '900', textTransform: 'uppercase', flex: 1, textAlign: 'center' }}>
          {game.away_team} <span style={{ color: '#9ca3af' }}>@</span> {game.home_team}
        </h1>
        <button onClick={clearKey} style={{ border: 'none', color: '#9ca3af', boxShadow: 'none', fontWeight: '900' }}>LOGOUT</button>
      </header>

      <main>
        <div className="tab-container">
          {availableMarkets.map(m => (
            <button key={m} onClick={() => setSelectedMarket(m)} className={`tab-item ${selectedMarket === m ? 'active' : ''}`}>
              {renderMarketLabelClean(m)}
            </button>
          ))}
        </div>

        {!loading && (
          <div style={{ display: 'flex', flexDirection: 'column', gap: '6px' }}>
            {analysis && (
              <div className="volatility-context" style={{ textAlign: 'left', padding: '12px', marginBottom: '12px' }}>
                <div className="label-tiny" style={{ marginBottom: '8px', color: 'var(--primary-text)', fontWeight: 900 }}>Market-Implied Script</div>
                <ul style={{ margin: 0, paddingLeft: '16px', fontSize: '10px', color: '#374151', fontWeight: 600 }}>
                  {analysis.gameScript.map((s, i) => <li key={i} style={{ marginBottom: '4px' }}>{s}</li>)}
                </ul>
              </div>
            )}

            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '12px', padding: '0 8px' }}>
               <div style={{ display: 'flex', alignItems: 'center', gap: '4px' }}>
                <span className="label-tiny">Sportsbook</span>
                <select value={selectedBookmaker} onChange={(e) => setSelectedBookmaker(e.target.value)} style={{ fontSize: '9px', fontWeight: '700', borderRadius: '4px', padding: '2px' }}>
                  {currentBookmakers.map(b => <option key={b.key} value={b.key}>{b.title}</option>)}
                </select>
              </div>
              <button onClick={handleAnalyze} disabled={analyzing} className={analyzing ? "" : "btn-primary-gradient"} style={{ fontSize: '9px', fontWeight: 900 }}>
                {analyzing ? 'STRUCTURAL SCAN...' : 'BUILD MARKET ANALYSIS'}
              </button>
            </div>

            {error && <div className="label-tiny" style={{ color: '#dc2626', textAlign: 'center', padding: '20px' }}>{error}</div>}

            <div className="team-group-grid">
              <div className="team-column">
                <div className="team-label">AWAY — <span>{game.away_team}</span></div>
                {awayPlayers.length === 0 && !loading && <div className="label-tiny" style={{ textAlign: 'center', padding: '10px' }}>No Props Found</div>}
                {awayPlayers.map(renderPlayerCard)}
              </div>
              <div className="team-column">
                <div className="team-label">HOME — <span>{game.home_team}</span></div>
                {homePlayers.length === 0 && !loading && <div className="label-tiny" style={{ textAlign: 'center', padding: '10px' }}>No Props Found</div>}
                {homePlayers.map(renderPlayerCard)}
              </div>
            </div>
          </div>
        )}
        {loading && <div className="label-tiny" style={{ textAlign: 'center', padding: '40px' }}>Updating Data Stream...</div>}
      </main>
    </div>
  );
};

